class Solution:
    def countPairs(self, coordinates: List[List[int]], k: int) -> int:
        from collections import defaultdict

        count = 0
        freq = defaultdict(int)

        for x, y in coordinates:
            for x1 in range(x ^ k, x ^ k + k + 1):
                y1 = (x ^ x1) + (y ^ k)
                count += freq[(x1, y1)]
            freq[(x, y)] += 1

        return count
